def get_2020_wiki_snippet(topic, min_words=80, max_words=120):
    url = "https://en.wikipedia.org/w/api.php"
    headers = {
        'User-Agent': 'UniversityResearchBot/1.0 (mailto:random@gmail.com) python-requests/2.0'
    }
    
    try:
        search_params = {
            "action": "query", "list": "search", "srsearch": topic,
            "format": "json", "srlimit": 1
        }
        res_search = requests.get(url, headers=headers, params=search_params)
        
        if res_search.status_code == 429:
            print("  -> Rate limited by Wikipedia! Pausing for 15 seconds...")
            time.sleep(15)
            return None
            
        search_res = res_search.json()
        
        if not search_res.get('query', {}).get('search'):
            return None 
            
        real_title = search_res['query']['search'][0]['title']
        
        params = {
            "action": "query", "prop": "revisions", "titles": real_title,
            "rvprop": "content", "rvlimit": "1", "rvstart": "2020-12-31T23:59:59Z",
            "rvdir": "older", "format": "json"
        }
        
        res_page = requests.get(url, headers=headers, params=params)
        
        if res_page.status_code == 429:
            print("  -> Rate limited by Wikipedia! Pausing for 15 seconds...")
            time.sleep(15)
            return None
            
        response = res_page.json()
        pages = response['query']['pages']
        page_id = list(pages.keys())[0]
        
        if page_id == '-1' or 'revisions' not in pages[page_id]: 
            return None
            
        wikitext = pages[page_id]['revisions'][0]['*']
        clean_text = mwparserfromhell.parse(wikitext)
        
        # --- DESTROY ALL IMAGES AND CAPTIONS ---
        for wikilink in clean_text.filter_wikilinks():
            if wikilink.title.strip().lower().startswith(('file:', 'image:')):
                try:
                    clean_text.remove(wikilink)
                except ValueError:
                    pass
                    
        # --- DESTROY ALL INLINE CITATIONS ---
        for tag in clean_text.filter_tags():
            if tag.tag == "ref":
                try:
                    clean_text.remove(tag)
                except ValueError:
                    pass
        # ----------------------------------------------------
        
        # Now strip the code (the image captions are already gone!)
        clean_text = clean_text.strip_code()
        
        # Final cleanup for rogue spaces or brackets
        clean_text = re.sub(r'\{.*?\}', '', clean_text) 
        clean_text = re.sub(r'\s+', ' ', clean_text).strip()
        
        sentences = clean_text.split('. ')
        
        # --- THE FIX: Scrub Wikipedia Image/Formatting Artifacts ---
        clean_text = re.sub(r'\b(?:thumb|left|right|center|upright[\=\d\.]*|\d+x?\d*px)\s*\|', '', clean_text)
        clean_text = clean_text.replace('|', '')
        # -----------------------------------------------------------
        
        clean_text = re.sub(r'\{.*?\}', '', clean_text) 
        clean_text = re.sub(r'\s+', ' ', clean_text).strip()
        
        sentences = clean_text.split('. ')
        current_chunk = ""
        
        for sentence in sentences:
            if not sentence: continue
            chunk_to_test = current_chunk + sentence + "."
            word_count = len(chunk_to_test.split())
            
            if min_words <= word_count <= max_words:
                return chunk_to_test.strip()
            
            current_chunk += sentence + ". "
            if word_count > max_words:
                break 
                
        words = clean_text.split()
        if len(words) >= 100:
            return " ".join(words[:100]) + "."
        return clean_text
        
    except ValueError:
        print("  -> Received non-JSON response. Pausing for 5 seconds...")
        time.sleep(5)
        return None
    except Exception:
        return None

