for topic in topics_list:
    # Skip if we already tried this one
    if topic in attempted_topics:
        continue
        
    snippet = get_2020_wiki_snippet(topic)
    
    if snippet:
        # Save to our working list
        pure_human_data.append({
            'Topic': topic, # Keeping topic for tracking purposes right now
            'Text': snippet, 
            'Label': 'Human'
        })
        print(f"[{len(pure_human_data)}] Success: {topic}")
        
        # Save the updated CSV immediately to disk
        pd.DataFrame(pure_human_data).to_csv(progress_file, index=False, sep=';')
    else:
        print(f"Failed to find valid text for: {topic}")
        
    # Mark as attempted in the text file
    with open(attempted_file, 'a', encoding='utf-8') as f:
        f.write(topic + "\n")
        
    # Add topic to our set so it doesn't get processed again in this run
    attempted_topics.add(topic)
    
    time.sleep(1.0) # Be polite to Wikipedia!

